// Parse the JSON output from garmin_fetch.py and surface it cleanly.
// Exit code != 0 will already cause the Execute Command node to fail;
// this node just makes the result readable in the execution log.

const raw = $input.first().json.stdout ?? '';

let result;
try {
  result = JSON.parse(raw);
} catch (_) {
  result = { status: 'error', message: 'Could not parse script output', raw };
}

if (result.status === 'error') {
  throw new Error(
    `Garmin fetch errors: ${(result.errors ?? [result.message]).join('; ')}`
  );
}

console.log(
  `Garmin sync complete: +${result.activities_added} activities, ` +
  `+${result.sleep_days_added} sleep days, ` +
  `+${result.hrv_days_added} HRV days, ` +
  `+${result.rhr_days_added} RHR days (${result.date_range})`
);

return [{ json: result }];
